t.script:

// ── Element refs ─────────────────────────────────
const sidebar       = document.getElementById('sidebar');
const overlay       = document.getElementById('sidebar-overlay');
const toggleBtn     = document.getElementById('sidebar-toggle-btn');

// ── Breakpoint helper ────────────────────────────
function isMobile() {
    return window.innerWidth <= 768;
}

// ── Sidebar state ────────────────────────────────
// Desktop uses .collapsed (width: 0 slide)
// Mobile  uses .open     (transform slide-in)
const SIDEBAR_KEY = 'dragon_sidebar_open';

function isSidebarOpen() {
    if (isMobile()) {
        return sidebar.classList.contains('open');
    }
    return !sidebar.classList.contains('collapsed');
}

function openSidebar() {
    if (isMobile()) {
        sidebar.classList.add('open');
        overlay.classList.add('visible');
    } else {
        sidebar.classList.remove('collapsed');
    }
    try { localStorage.setItem(SIDEBAR_KEY, '1'); } catch(e) {}
}

function closeSidebar() {
    if (isMobile()) {
        sidebar.classList.remove('open');
        overlay.classList.remove('visible');
    } else {
        sidebar.classList.add('collapsed');
    }
    try { localStorage.setItem(SIDEBAR_KEY, '0'); } catch(e) {}
}

function toggleSidebar() {
    if (isSidebarOpen()) {
        closeSidebar();
    } else {
        openSidebar();
    }
}

// Re-sync sidebar state when viewport crosses mobile breakpoint
window.addEventListener('resize', function () {
    if (!isMobile()) {
        // Switching to desktop: clear mobile .open, restore desktop state
        sidebar.classList.remove('open');
        overlay.classList.remove('visible');
        try {
            if (localStorage.getItem(SIDEBAR_KEY) === '0') {
                sidebar.classList.add('collapsed');
            } else {
                sidebar.classList.remove('collapsed');
            }
        } catch(e) {}
    } else {
        // Switching to mobile: clear desktop .collapsed
        sidebar.classList.remove('collapsed');
    }
});

// Restore last sidebar state on load
(function restoreSidebarState() {
    try {
        const saved = localStorage.getItem(SIDEBAR_KEY);
        if (isMobile()) {
            // Mobile: always start closed (no .open), overlay hidden
            sidebar.classList.remove('open');
        } else {
            // Desktop: restore saved preference, default open
            if (saved === '0') {
                sidebar.classList.add('collapsed');
            }
        }
    } catch(e) {}
})();

// ── Toggle button click ──────────────────────────
toggleBtn.addEventListener('click', toggleSidebar);

// ── Mobile overlay click closes sidebar ──────────
overlay.addEventListener('click', closeSidebar);

// ── New Chat button ──────────────────────────────
document.getElementById('new-chat-btn').addEventListener('click', function () {
    const chatBox = document.getElementById('chat-box');
    chatBox.innerHTML = '';
    // Always close sidebar after tapping New Chat on mobile
    if (isMobile()) closeSidebar();
    if (typeof window.resetChat === 'function') window.resetChat();
});

// ── Chat history helper (called from chatbot.js) ──
window.addChatToHistory = function (previewText) {
    const historyEl = document.getElementById('chat-history');
    const emptyEl   = document.getElementById('history-empty');
    if (emptyEl) emptyEl.remove();

    // Remove active class from others
    document.querySelectorAll('.history-item').forEach(el => el.classList.remove('active'));

    const item = document.createElement('div');
    item.className = 'history-item active';
    item.innerHTML = `
        <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke-width="1.5" stroke="currentColor">
            <path stroke-linecap="round" stroke-linejoin="round" d="M2.25 12.76c0 1.6 1.123 2.994 2.707 3.227 1.087.16 2.185.283 3.293.369V21l4.076-4.076a1.526 1.526 0 011.037-.443 48.282 48.282 0 005.68-.494c1.584-.233 2.707-1.626 2.707-3.228V6.741c0-1.602-1.123-2.995-2.707-3.228A48.394 48.394 0 0012 3c-2.392 0-4.744.175-7.043.513C3.373 3.746 2.25 5.14 2.25 6.741v6.018z"/>
        </svg>
        <span class="history-item-text">${previewText.substring(0, 32)}${previewText.length > 32 ? '…' : ''}</span>
    `;
    historyEl.prepend(item);
};

// ── appendBotMessage helper ───────────────────────
// Call this from chatbot.js instead of manually building DOM.
// It creates a right-aligned bot message row with the dragon avatar.
window.appendBotMessage = function (text, timestamp) {
    const chatBox = document.getElementById('chat-box');

    // Remove typing indicator if present
    const typing = document.getElementById('typing-indicator');
    if (typing) typing.remove();

    const time = timestamp || new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

    const row = document.createElement('div');
    row.className = 'message-row bot-row';
    row.innerHTML = `
        <div class="msg-avatar" id="bot-msg-avatar">🐉</div>
        <div class="message-content-wrap">
            <span class="msg-sender">Dragon Chat</span>
            <div class="message-bubble bot-bubble">${text}</div>
            <span class="msg-timestamp">${time}</span>
        </div>
    `;
    chatBox.appendChild(row);
    chatBox.scrollTop = chatBox.scrollHeight;

    // Swap emoji for logo image if one has been set
    if (window._logoSrc) {
        const av = row.querySelector('#bot-msg-avatar');
        if (av) av.innerHTML = `<img src="${window._logoSrc}" alt="Dragon Coders" />`;
    }
};

// ── appendUserMessage helper ──────────────────────
// Mirrors appendBotMessage for user messages (left-aligned, dark bubble).
window.appendUserMessage = function (text, timestamp) {
    const chatBox = document.getElementById('chat-box');
    const time = timestamp || new Date().toLocaleTimeString([], { hour: '2-digit', minute: '2-digit' });

    const row = document.createElement('div');
    row.className = 'message-row user-row';
    row.innerHTML = `
        <div class="message-content-wrap">
            <span class="msg-sender">You</span>
            <div class="message-bubble user-bubble">${text}</div>
            <span class="msg-timestamp">${time}</span>
        </div>
    `;
    chatBox.appendChild(row);
    chatBox.scrollTop = chatBox.scrollHeight;
};

// ── showTypingIndicator helper ────────────────────
window.showTypingIndicator = function () {
    const chatBox = document.getElementById('chat-box');
    if (document.getElementById('typing-indicator')) return;

    const row = document.createElement('div');
    row.className = 'typing-row';
    row.id = 'typing-indicator';
    row.innerHTML = `
        <div class="msg-avatar">${window._logoSrc ? '<img src="' + window._logoSrc + '" alt="Dragon Coders"/>' : '🐉'}</div>
        <div class="typing-bubble">
            <span class="typing-dot"></span>
            <span class="typing-dot"></span>
            <span class="typing-dot"></span>
        </div>
    `;
    chatBox.appendChild(row);
    chatBox.scrollTop = chatBox.scrollHeight;
};

// ── Logo swap helper ──────────────────────────────
window.setLogo = function (src) {
    window._logoSrc = src;
    ['sidebar-logo', 'header-logo'].forEach(function (id) {
        const el = document.getElementById(id);
        if (el) el.innerHTML = '<img src="' + src + '" alt="Dragon Coders Logo"/>';
    });
};
